function solve(s, order, k) {
    const n = s.length;
    if (k === 0) {
        return 0;
    }
    const totalSubstrings = n * (n + 1) / 2;
    if (k > totalSubstrings) {
        return -1;
    }

    let low = 0;
    let high = n - 1;
    let answer = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const tempMarked = new Array(n).fill(false);
        for (let i = 0; i <= mid; i++) {
            tempMarked[order[i]] = true;
        }

        let count = 0;
        let currentStreak = 0;
        for (let i = 0; i < n; i++) {
            if (tempMarked[i]) {
                currentStreak += 1;
            } else {
                currentStreak = 0;
            }
            count += currentStreak;
        }

        if (count >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
